namespace Store;

public sealed class ShoppingCart
{
    private readonly Dictionary<string, (int Quantity, decimal Price)> _items = new();
    private decimal _discountPercent;

    public void AddItem(string sku, int quantity, decimal price)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (quantity <= 0) throw new ArgumentOutOfRangeException(nameof(quantity));
        if (price < 0) throw new ArgumentOutOfRangeException(nameof(price));

        if (_items.TryGetValue(sku, out var existing))
            _items[sku] = (existing.Quantity + quantity, price);
        else
            _items[sku] = (quantity, price);
    }

    public void RemoveItem(string sku)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (!_items.Remove(sku))
            throw new InvalidOperationException($"Item '{sku}' not found in cart.");
    }

    public decimal CalculateTotal()
    {
        var subtotal = _items.Values.Sum(item => item.Quantity * item.Price);
        return subtotal - (subtotal * _discountPercent / 100m);
    }

    public void ApplyCoupon(string code)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(code);
        _discountPercent = code.ToUpperInvariant() switch
        {
            "SAVE10" => 10m,
            "SAVE20" => 20m,
            _ => throw new ArgumentException($"Invalid coupon code: '{code}'.", nameof(code))
        };
    }
}

using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ── AddItem ────────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("B", 3, 5m);

        Assert.AreEqual(25m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_AccumulatesQuantity()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("A", 2, 10m);

        Assert.AreEqual(30m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuWithNewPrice_UsesLatestPrice()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("A", 1, 15m);

        // 2 units at the updated price of 15
        Assert.AreEqual(30m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroPriceItem_IsAllowed()
    {
        _cart.AddItem("FREE", 1, 0m);

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(null!, 1, 10m));
    }

    [TestMethod]
    public void AddItem_EmptySku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("", 1, 10m));
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", 0, 10m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", -1, 10m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", 1, -5m));
    }

    // ── RemoveItem ─────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_DecreasesTotal()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("B", 1, 20m);

        _cart.RemoveItem("A");

        Assert.AreEqual(20m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalBecomesZero()
    {
        _cart.AddItem("A", 5, 10m);

        _cart.RemoveItem("A");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_Throws()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("MISSING"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.RemoveItem(null!));
    }

    [TestMethod]
    public void RemoveItem_AlreadyRemovedItem_Throws()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.RemoveItem("A");

        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("A"));
    }

    // ── CalculateTotal ─────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_IsCorrect()
    {
        _cart.AddItem("A", 2, 10m);
        _cart.AddItem("B", 1, 5m);
        _cart.RemoveItem("B");

        Assert.AreEqual(20m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ────────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_Save10_Applies10PercentDiscount()
    {
        _cart.AddItem("A", 1, 100m);

        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(90m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Save20_Applies20PercentDiscount()
    {
        _cart.AddItem("A", 1, 50m);

        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(40m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_IsCaseInsensitive()
    {
        _cart.AddItem("A", 1, 100m);

        _cart.ApplyCoupon("save10");

        Assert.AreEqual(90m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_ReplacedByNewerCoupon()
    {
        _cart.AddItem("A", 1, 100m);
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(""));
    }

    // ── Integration / combined scenarios ───────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCoupon_ProducesCorrectTotal()
    {
        _cart.AddItem("WIDGET", 3, 12.50m); // 37.50
        _cart.AddItem("GADGET", 1, 25.00m); // 25.00
        _cart.RemoveItem("GADGET");          // -25.00
        _cart.ApplyCoupon("SAVE10");         // 10% off 37.50

        Assert.AreEqual(33.75m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CouponAppliedBeforeAddingItems_StillDiscounts()
    {
        _cart.ApplyCoupon("SAVE20");
        _cart.AddItem("A", 2, 50m);

        Assert.AreEqual(80m, _cart.CalculateTotal());
    }
}

